1	package bind
2	
3	import (
4		"crypto/rand"
5		"io"
6		"net/netip"
7		"testing"
8		"time"
9	
10		"github.com/7mind/wanbond/internal/config"
11		"github.com/7mind/wanbond/internal/frame"
12		"github.com/7mind/wanbond/internal/log"
13		"github.com/7mind/wanbond/internal/sched"
14		"github.com/7mind/wanbond/internal/telemetry"
15	)
16	
17	// bindSecondPeer constructs a SECOND peerState over the SAME shared sockets an already-Open
18	// Multipath holds, and binds it into m.peers/m.peersByName. It stands in for the concentrator's
19	// per-peer wiring (a later G4 task) so this test can exercise the runtime shared-path fan-out
20	// while >=2 peerStates are bound: it gives the peer its own DynamicScheduler, its own probe
21	// initiator factory + boot probers (aligned with the durable membership m.defs), and a
22	// peerPathState VIEW over each currently-bound shared socket. It must run after m.Open.
23	func bindSecondPeer(t testing.TB, m *Multipath, name string, psk config.Key, clk telemetry.Clock) *peerState {
24		t.Helper()
25		lg, err := log.New("error", io.Discard)
26		if err != nil {
27			t.Fatalf("build logger: %v", err)
28		}
29		cfg := telemetry.ProberConfig{
30			LossWindow: 0,
31			Liveness:   telemetry.LivenessConfig{DownAfter: testProbeDownAfter, UpAfterSuccesses: testProbeUpSucc},
32		}
33		// A DISTINCT probe session id from the primary's: a concentrator peer runs its own probe
34		// session, and it proves the fan-out mints genuinely per-peer probers (not shared handles).
35		const secondPeerSessionID uint64 = 0x0123456789ABCDEF
36		newProber := func(pname string, id uint8) *telemetry.Prober {
37			return telemetry.NewProber(pname, id, secondPeerSessionID, psk, cfg, clk, lg)
38		}
39	
40		m.mu.Lock()
41		defer m.mu.Unlock()
42	
43		// Boot probers aligned with the durable membership (m.defs), stamped with each shared
44		// socket's path-id so DATA and PROBE agree on the wire, exactly as Open does for the primary.
45		probers := make([]*telemetry.Prober, len(m.defs))
46		health := make([]sched.PathHealth, len(m.defs))
47		byName := make(map[string]*telemetry.Prober, len(m.defs))
48		for i := range m.defs {
49			var id uint8
50			for _, sp := range m.shared {
51				if sp.name == m.defs[i].Name {
52					id = sp.id
53				}
54			}
55			probers[i] = newProber(m.defs[i].Name, id)
56			health[i] = probers[i]
57			byName[m.defs[i].Name] = probers[i]
58		}
59		scheduler, err := sched.NewActiveBackup(health, sched.Config{FailbackAfter: time.Hour}, clk, lg)
60		if err != nil {
61			t.Fatalf("build second-peer scheduler: %v", err)
62		}
63		sendCodec, err := frame.NewCodec(psk)
64		if err != nil {
65			t.Fatalf("build second-peer send codec: %v", err)
66		}
67		p := &peerState{
68			name:      name,
69			virt:      &udpEndpoint{},
70			scheduler: scheduler,
71			reflector: telemetry.NewReflector(psk, rand.Reader),
72			newProber: newProber,
73			probers:   probers,
74			sendCodec: sendCodec,
75		}
76		// A peerPathState VIEW over each bound shared socket, index-aligned with m.shared (which,
77		// with no deferred paths, is also aligned with m.defs) so the peer's scheduler and paths
78		// stay index-aligned exactly as the primary's do.
79		for _, sp := range m.shared {
80			codec, cerr := frame.NewCodec(psk)
81			if cerr != nil {
82				t.Fatalf("build second-peer path codec: %v", cerr)
83			}
84			p.paths = append(p.paths, &peerPathState{sharedPathState: sp, peer: p, codec: codec, prober: byName[sp.name]})
85		}
86		m.peers = append(m.peers, p)
87		m.peersByName[name] = p
88		return p
89	}
90	
91	// pathNamesOfPeer snapshots a peer's per-(peer,path) view names, for assertions.
92	func pathNamesOfPeer(p *peerState) []string {
93		out := make([]string, len(p.paths))
94		for i, pp := range p.paths {
95			out[i] = pp.name
96		}
97		return out
98	}
99	
100	// peerPathByName returns the peer's per-(peer,path) view of the named shared path, or nil.
101	func peerPathByName(p *peerState, name string) *peerPathState {
102		for _, pp := range p.paths {
103			if pp.name == name {
104				return pp
105			}
106		}
107		return nil
108	}
109	
110	// TestMultipathSharedPathFanOutAcrossPeers is the G4 fan-out acceptance for the peerState /
111	// pathState split: with TWO peerStates bound over the same shared sockets, a runtime AddPath of
112	// a SHARED path must instantiate per-(peer,path) state (codec, remote, prober, tx/rx) for BOTH
113	// peers, and a runtime RemovePath must tear that per-(peer,path) state down for BOTH peers,
114	// leaving each peer's remaining paths untouched. It proves the fan-out has a single owner
115	// (attachSharedPathLocked / RemovePath) exercised while >=2 peerStates exist.
116	func TestMultipathSharedPathFanOutAcrossPeers(t *testing.T) {
117		psk := testKey(t, 0x41)
118		clk := newFakeClock()
119		m, _, _ := newProbingMultipath(t, loopbackPaths(1), psk, clk) // one shared path, "a"
120		if _, _, err := m.Open(0); err != nil {
121			t.Fatalf("Open: %v", err)
122		}
123		t.Cleanup(func() { _ = m.Close() })
124	
125		primary := m.peerState
126		second := bindSecondPeer(t, m, "peer-2", psk, clk)
127	
128		// Preconditions: two bound peers, each with exactly the one boot path "a" over the one
129		// shared socket. Capture each peer's original path object to prove the remove leaves it
130		// untouched.
131		if len(m.peers) != 2 {
132			t.Fatalf("bound peers = %d, want 2", len(m.peers))
133		}
134		if len(m.shared) != 1 {
135			t.Fatalf("shared sockets = %d, want 1", len(m.shared))
136		}
137		primaryOrigA := peerPathByName(primary, "a")
138		secondOrigA := peerPathByName(second, "a")
139		if primaryOrigA == nil || secondOrigA == nil {
140			t.Fatalf("boot path 'a' missing: primary=%v second=%v", pathNamesOfPeer(primary), pathNamesOfPeer(second))
141		}
142		if primaryOrigA.sharedPathState != secondOrigA.sharedPathState {
143			t.Fatal("the two peers' boot path 'a' must VIEW the same shared socket")
144		}
145	
146		// --- AddPath a SHARED path at runtime: the fan-out must reach BOTH peers. ---
147		if err := m.AddPath(config.Path{Name: "shared-b", SourceAddr: netip.MustParseAddr("127.0.0.1")}); err != nil {
148			t.Fatalf("AddPath: %v", err)
149		}
150		if len(m.shared) != 2 {
151			t.Fatalf("shared sockets after add = %d, want 2", len(m.shared))
152		}
153		sharedB := m.shared[1]
154		if sharedB.name != "shared-b" {
155			t.Fatalf("new shared socket name = %q, want %q", sharedB.name, "shared-b")
156		}
157	
158		for _, tc := range []struct {
159			who string
160			p   *peerState
161		}{{"primary", primary}, {"second", second}} {
162			pp := peerPathByName(tc.p, "shared-b")
163			if pp == nil {
164				t.Fatalf("%s peer has no per-(peer,path) state for 'shared-b' after add (fan-out missed it): %v", tc.who, pathNamesOfPeer(tc.p))
165			}
166			// Per-(peer,path) state was instantiated: its OWN codec + prober, VIEWING the ONE shared
167			// socket (not a duplicate socket per peer).
168			if pp.sharedPathState != sharedB {
169				t.Fatalf("%s peer's 'shared-b' does not view the shared socket (per-peer socket duplicated)", tc.who)
170			}
171			if pp.codec == nil {
172				t.Fatalf("%s peer's 'shared-b' has no per-(peer,path) codec", tc.who)
173			}
174			if pp.prober == nil {
175				t.Fatalf("%s peer's 'shared-b' has no per-(peer,path) prober", tc.who)
176			}
177			if pp.peer != tc.p {
178				t.Fatalf("%s peer's 'shared-b' back-references the wrong peerState", tc.who)
179			}
180		}
181		// The two peers minted DISTINCT probers for the shared path (genuine per-(peer,path) state,
182		// not one shared handle).
183		if peerPathByName(primary, "shared-b").prober == peerPathByName(second, "shared-b").prober {
184			t.Fatal("both peers share ONE prober for 'shared-b' — the fan-out did not mint per-peer state")
185		}
186	
187		// --- RemovePath the shared path: the teardown must reach BOTH peers. ---
188		if err := m.RemovePath("shared-b"); err != nil {
189			t.Fatalf("RemovePath: %v", err)
190		}
191		if len(m.shared) != 1 {
192			t.Fatalf("shared sockets after remove = %d, want 1", len(m.shared))
193		}
194		for _, tc := range []struct {
195			who  string
196			p    *peerState
197			orig *peerPathState
198		}{{"primary", primary, primaryOrigA}, {"second", second, secondOrigA}} {
199			if peerPathByName(tc.p, "shared-b") != nil {
200				t.Fatalf("%s peer still holds per-(peer,path) state for 'shared-b' after remove: %v", tc.who, pathNamesOfPeer(tc.p))
201			}
202			if len(tc.p.paths) != 1 {
203				t.Fatalf("%s peer path count after remove = %d, want 1 (remaining paths untouched)", tc.who, len(tc.p.paths))
204			}
205			remaining := peerPathByName(tc.p, "a")
206			if remaining == nil {
207				t.Fatalf("%s peer lost its remaining path 'a' on the remove: %v", tc.who, pathNamesOfPeer(tc.p))
208			}
209			if remaining != tc.orig {
210				t.Fatalf("%s peer's remaining path 'a' object changed on the remove (remaining paths must be untouched)", tc.who)
211			}
212		}
213	}
