22	// newMultipath builds a Multipath over paths with a default active-backup
23	// scheduler whose paths are all statically Up, so path selection reduces to the
24	// preferred primary (index 0) — the T12 send behaviour these tests assert. The
25	// scheduler's own failover/hysteresis logic is exercised in internal/sched. It
26	// passes no probers, so the probe transport is inert here (exercised separately
27	// in probe_test.go).
28	func newMultipath(t testing.TB, paths []config.Path, psk config.Key) (*Multipath, error) {
29		t.Helper()
30		health := make([]sched.PathHealth, len(paths))
31		for i := range health {
32			health[i] = sched.AlwaysUp{}
33		}
34		lg, err := log.New("error", io.Discard)
35		if err != nil {
36			t.Fatalf("build logger: %v", err)
37		}
38		scheduler, err := sched.NewActiveBackup(health, sched.Config{FailbackAfter: time.Second}, telemetry.SystemClock{}, lg)
39		if err != nil {
40			t.Fatalf("build scheduler: %v", err)
41		}
42		return NewMultipath(paths, psk, scheduler, nil, nil, nil, nil, config.Amnezia{})
43	}
