69	// sendDataTo encodes a DATA frame under psk and sends it from a fresh client
70	// socket to dst, returning the client's local AddrPort so the test can assert the
71	// path learned it.
72	func sendDataTo(t testing.TB, psk config.Key, dst *net.UDPAddr, pathID uint8, payload []byte) netip.AddrPort {
73		t.Helper()
74		cl, err := net.DialUDP("udp", &net.UDPAddr{IP: net.ParseIP("127.0.0.1")}, dst)
75		if err != nil {
76			t.Fatalf("dial %s: %v", dst, err)
77		}
78		defer cl.Close()
79		codec, err := frame.NewCodec(psk)
80		if err != nil {
81			t.Fatalf("new codec: %v", err)
82		}
83		wire, err := codec.Encode(nil, frame.Data{OuterSeq: uint64(pathID), PathID: pathID, Payload: payload})
84		if err != nil {
85			t.Fatalf("encode: %v", err)
86		}
87		if _, err := cl.Write(wire); err != nil {
88			t.Fatalf("write: %v", err)
89		}
90		return cl.LocalAddr().(*net.UDPAddr).AddrPort()
91	}
