93	// TestMultipathVirtualEndpointIdentity is the core §3 invariant: N per-path
94	// sockets deliver received datagrams under ONE stable virtual endpoint, so the
95	// engine never observes per-packet endpoint churn.
96	//
97	// Note it does NOT assert per-path remote learning from these DATA frames: after
98	// D9, remote-learning is authenticated-only (from PROBE/echo frames), so a DATA
99	// frame no longer teaches a path its return remote — that is asserted in
100	// probe_test.go (TestMultipathRemoteLearnedFromProbeNotData).
101	func TestMultipathVirtualEndpointIdentity(t *testing.T) {
102		psk := testKey(t, 0x5A)
103		m, err := newMultipath(t, loopbackPaths(2), psk)
104		if err != nil {
105			t.Fatalf("NewMultipath: %v", err)
106		}
107		// The fan-in receive model (T30) returns a SINGLE engine-facing ReceiveFunc
108		// regardless of path count: the Bind owns one reader per path internally, and the
109		// one drainer delivers every path's frames under the one virtual endpoint.
110		fns, _, err := m.Open(0)
111		if err != nil {
112			t.Fatalf("Open: %v", err)
113		}
114		t.Cleanup(func() { _ = m.Close() })
115		if len(fns) != 1 {
116			t.Fatalf("got %d receive funcs, want 1 (fan-in delivery)", len(fns))
117		}
118		fn := fns[0]
119	
120		// Send a DATA frame to EACH path's socket (OuterSeq i on path i); the Bind-owned
121		// readers read them and feed the shared resequencer, and the single drainer
122		// delivers both — under the SAME virtual endpoint.
123		//
124		// INTERLEAVE send+receive per path (defect D19): the two paths are read by
125		// INDEPENDENT reader goroutines with NO cross-path arrival ordering. If both
126		// frames were sent up front and OuterSeq 1 happened to be observed first, the
127		// resequencer would pin its release point to 1 and drop the later OuterSeq 0 as
128		// late — the second receive would then block forever. Sending OuterSeq i and
129		// receiving it before sending OuterSeq i+1 pins the release point deterministically
130		// (0 then 1), so both frames are delivered in order regardless of reader scheduling.
131		payload := []byte("opaque-wireguard-datagram")
132		var gotEps []Endpoint
133		for i := 0; i < 2; i++ {
134			dst := m.paths[i].conn.LocalAddr().(*net.UDPAddr)
135			sendDataTo(t, psk, dst, uint8(i), payload)
136	
137			bufs := [][]byte{make([]byte, 2048)}
138			sizes := make([]int, 1)
139			eps := make([]Endpoint, 1)
140			n, err := fn(bufs, sizes, eps)
141			if err != nil {
142				t.Fatalf("receive %d: %v", i, err)
143			}
144			if n != 1 {
145				t.Fatalf("receive %d: got n=%d, want 1", i, n)
146			}
147			if !bytes.Equal(bufs[0][:sizes[0]], payload) {
148				t.Fatalf("receive %d: inner payload = %q, want %q", i, bufs[0][:sizes[0]], payload)
149			}
150			gotEps = append(gotEps, eps[0])
151		}
152	
153		// Virtual-endpoint identity: both delivered frames carried the SAME endpoint.
154		if gotEps[0] != gotEps[1] {
155			t.Fatalf("deliveries returned different endpoints (%v vs %v): virtual-endpoint identity violated",
156				gotEps[0].DstToString(), gotEps[1].DstToString())
157		}
158	}
