160	// TestMultipathVirtualEndpointDstRace is the regression for the reproduced data
161	// race: the Bind pins the virtual endpoint's destination (via virtualEndpoint /
162	// ParseEndpoint) from receive goroutines while the engine reads that same field
163	// locklessly through the Dst* accessors. It pins from multiple goroutines while
164	// others hammer DstToBytes/DstToString/DstIP; under `go test -race` a plain
165	// (non-atomic) dst field trips the detector deterministically, and the atomic
166	// pointer makes it clean. T15's cross-path scheduling activates exactly this
167	// concurrency, so it is guarded here on the object T12 delivers.
168	func TestMultipathVirtualEndpointDstRace(t *testing.T) {
169		psk := testKey(t, 0x99)
170		m, err := newMultipath(t, loopbackPaths(4), psk)
171		if err != nil {
172			t.Fatalf("NewMultipath: %v", err)
173		}
174	
175		const (
176			writers = 4
177			readers = 4
178			iters   = 2000
179		)
180		var readersWg, writersWg sync.WaitGroup
181		stop := make(chan struct{})
182	
183		// Readers: the engine-facing lockless accessors, spinning until stopped.
184		for i := 0; i < readers; i++ {
185			readersWg.Add(1)
186			go func() {
187				defer readersWg.Done()
188				for {
189					select {
190					case <-stop:
191						return
192					default:
193					}
194					_ = m.virt.DstToBytes()
195					_ = m.virt.DstToString()
196					_ = m.virt.DstIP()
197				}
198			}()
199		}
200	
201		// Writers: pin the endpoint concurrently via the real Bind path (each with a
202		// distinct address) plus a direct setDst hammer, so repeated writes overlap
203		// the reads regardless of the once-guard.
204		for i := 0; i < writers; i++ {
205			writersWg.Add(1)
206			go func(id int) {
207				defer writersWg.Done()
208				ap := netip.AddrPortFrom(netip.AddrFrom4([4]byte{10, 0, 0, byte(id + 1)}), uint16(1000+id))
209				for j := 0; j < iters; j++ {
210					m.virtualEndpoint(ap) // real pin path (guarded, publishes atomically)
211					m.virt.setDst(ap)     // direct hammer to stress the accessor
212				}
213			}(i)
214		}
215	
216		writersWg.Wait() // writers finish; then release the readers
217		close(stop)
218		readersWg.Wait()
219	
220		// Sanity: after all the pinning, the endpoint has a valid destination.
221		if !m.virt.dstValid() {
222			t.Fatal("virtual endpoint destination never pinned")
223		}
224	}
