401		cases := []struct {
402			name string
403			pick int
404			want error
405		}{
406			{"paced shed", sched.PickPaced, errPacerShedding},
407			{"no eligible path", sched.PickNone, errNoHealthyPath},
408		}
409		for _, tc := range cases {
410			t.Run(tc.name, func(t *testing.T) {
411				m, err := NewMultipath(loopbackPaths(1), psk, stubScheduler{pick: tc.pick}, nil, nil, nil, nil, config.Amnezia{})
412				if err != nil {
