503	// rcvBuf reads SO_RCVBUF off a UDP socket via its raw file descriptor.
504	func rcvBuf(t *testing.T, c *net.UDPConn) int {
505		t.Helper()
506		raw, err := c.SyscallConn()
507		if err != nil {
508			t.Fatalf("SyscallConn: %v", err)
509		}
510		var val int
511		var sockErr error
512		if err := raw.Control(func(fd uintptr) {
513			val, sockErr = syscall.GetsockoptInt(int(fd), syscall.SOL_SOCKET, syscall.SO_RCVBUF)
514		}); err != nil {
515			t.Fatalf("raw control: %v", err)
516		}
517		if sockErr != nil {
518			t.Fatalf("getsockopt SO_RCVBUF: %v", sockErr)
519		}
520		return val
521	}
522	
523	// TestNewMultipathRejectsUnpairedProberFactory pins the constructor pairing invariant
524	// (fable low defect): a runtime-path factory (newProber) without a boot-time prober
525	// slice would let AddPath append to a nil m.probers, desyncing m.paths from m.probers
526	// and panicking on the next Open at m.probers[i]. NewMultipath must reject the pairing.
527	func TestNewMultipathRejectsUnpairedProberFactory(t *testing.T) {
528		psk := testKey(t, 0x37)
529		paths := loopbackPaths(1)
530		health := []sched.PathHealth{sched.AlwaysUp{}}
531		lg, err := log.New("error", io.Discard)
532		if err != nil {
533			t.Fatalf("build logger: %v", err)
534		}
535		scheduler, err := sched.NewActiveBackup(health, sched.Config{FailbackAfter: time.Second}, telemetry.SystemClock{}, lg)
536		if err != nil {
537			t.Fatalf("build scheduler: %v", err)
538		}
539		factory := func(name string, id uint8) *telemetry.Prober { return nil }
540		if _, err := NewMultipath(paths, psk, scheduler, nil, factory, nil, nil, config.Amnezia{}); err == nil {
541			t.Fatal("NewMultipath(newProber!=nil, probers==nil) succeeded, want rejection")
542		}
543	}
